sql:
SELECT SUM(amount) AS total_scholarship_harvest
FROM financial_aid
WHERE type = 'scholarship';

external_knowledge:
High graduation rate; substantial average graduate salary; excellent job placement; 
- 'High graduation rate' refers to a completion rate greater than 70%;
- 'Substantial average graduate salary' refers to an average salary greater than $50,000;
- 'Excellent job placement' refers to a job placement rate greater than 80%;
- 'Financial investment' refers to the total amount of payments.
